import React from "react";
import { Link } from "react-router-dom";
import "../styles/projects.css";

function Projects() {
  const projectItems = [
    {
      title: "Zerodha Clone",
      image: "/assets/zerodhaclone.png",
      description:
        "A clone of the Zerodha trading platform built with React and Node.js.",
      link: "/projects/zerodha",
    },
    {
      title: "Portfolio Dashboard",
      image: "/assets/zoomclone.png",
      description:
        "A personal portfolio dashboard with modular components and responsive UI.",
      link: "/github",
    },
  ];

  return (
    <main className="projects-wrap">
      <section className="projects-card">
        <p className="projects-eyebrow">Work</p>
        <h1>Projects</h1>
        <p className="projects-subtitle">
          Selected projects showcasing my full-stack and frontend work.
        </p>

        <div className="projects-grid">
          {projectItems.map((project) => (
            <article className="project-item" key={project.title}>
              <div className="project-image-shell">
                <img src={project.image} alt={project.title} />
              </div>
              <h2>{project.title}</h2>
              <p>{project.description}</p>
              <Link to={project.link} className="project-btn">
                View Project
              </Link>
            </article>
          ))}
        </div>

        <Link to="/github" className="projects-all-btn">
          View All Projects
        </Link>
      </section>
    </main>
  );
}

export default Projects;
